// ── Main ──────────────────────────────────────────────────────────────
async function main() {
  console.log(`\nPreparing to insert ${newFirms.length} firms...\n`);

  // 1. Fetch existing firms for duplicate check
  const { data: existing, error: fetchErr } = await supabase
    .from('firms')
    .select('slug, name, website');

  if (fetchErr) {
    console.error('Failed to fetch existing firms:', fetchErr.message);
    process.exit(1);
  }

  const existingNames = new Set(existing.map((f) => f.name.toLowerCase()));
  const existingWebsites = new Set(
    existing.filter((f) => f.website).map((f) => f.website.replace(/\/+$/, '').toLowerCase())
  );
  const existingSlugs = new Set(existing.map((f) => f.slug));

  // 2. Filter out duplicates
  const toInsert = [];
  const skipped = [];

  for (const firm of newFirms) {
    const normName = firm.name.toLowerCase();
    const normWeb = firm.website ? firm.website.replace(/\/+$/, '').toLowerCase() : '';

    if (existingSlugs.has(firm.slug)) {
      skipped.push({ name: firm.name, reason: 'duplicate slug' });
    } else if (existingNames.has(normName)) {
      skipped.push({ name: firm.name, reason: 'duplicate name' });
    } else if (normWeb && existingWebsites.has(normWeb)) {
      skipped.push({ name: firm.name, reason: 'duplicate website' });
    } else {
      toInsert.push({
        slug: firm.slug,
        name: firm.name,
        contact: firm.contact || null,
        title: firm.title || null,
        email: firm.email || null,
        city: firm.city,
        city_label: firm.cityLabel,
        province: firm.province,
        country: firm.country,
        services: firm.services || [],
        industries: firm.industries || [],
        description: firm.description || null,
        website: firm.website || null,
        plan: 'free',
        priority_score: 0,
        status: 'active',
        submitted_by: 'admin',
        source: firm.source || 'claude_code',
      });

      // Track so subsequent entries in this batch also check
      existingSlugs.add(firm.slug);
      existingNames.add(normName);
      if (normWeb) existingWebsites.add(normWeb);
    }
  }

  if (skipped.length) {
    console.log(`Skipped ${skipped.length} duplicates:`);
    skipped.forEach((s) => console.log(`  ✗ ${s.name} — ${s.reason}`));
    console.log('');
  }

  if (!toInsert.length) {
    console.log('No new firms to insert.');
    return;
  }

  // 3. Insert in batches of 50
  const BATCH = 50;
  let inserted = 0;

  for (let i = 0; i < toInsert.length; i += BATCH) {
    const batch = toInsert.slice(i, i + BATCH);
    const { error } = await supabase.from('firms').insert(batch);
    if (error) {
      console.error(`✗ Batch ${Math.floor(i / BATCH) + 1} failed:`, error.message);
    } else {
      inserted += batch.length;
      console.log(`✓ Inserted batch ${Math.floor(i / BATCH) + 1}: ${batch.length} firms`);
    }
  }

  console.log(`\n✓ Total inserted: ${inserted} firms`);

  // 4. Stats
  console.log('\n── Stats ──────────────────────────────────────────');
  const { count: total } = await supabase
    .from('firms')
    .select('*', { count: 'exact', head: true });
  console.log(`Total firms: ${total}`);

  const { data: allFirms } = await supabase
    .from('firms')
    .select('city, city_label, country, email');

  // Count by country
  const byCountry = {};
  allFirms.forEach((f) => {
    byCountry[f.country] = (byCountry[f.country] || 0) + 1;
  });
  console.log('\nBy country:');
  Object.entries(byCountry)
    .sort((a, b) => b[1] - a[1])
    .forEach(([c, n]) => console.log(`  ${c}: ${n}`));

  // Top 30 cities
  const byCity = {};
  allFirms.forEach((f) => {
    const key = f.city_label || f.city;
    byCity[key] = (byCity[key] || 0) + 1;
  });
  console.log('\nTop 30 cities:');
  Object.entries(byCity)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 30)
    .forEach(([c, n], i) => console.log(`  ${i + 1}. ${c}: ${n}`));

  // Emails
  const withEmail = allFirms.filter((f) => f.email).length;
  console.log(`\nFirms with email: ${withEmail} / ${allFirms.length}`);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
